import{_ as a,o as e,c as s,ae as t}from"./chunks/framework.C7FLYIpo.js";const p=JSON.parse('{"title":"음성 웨이크","description":"전역 음성 웨이크 단어 (게이트웨이 소유) 및 노드 간 동기화 방법","frontmatter":{"title":"음성 웨이크","description":"전역 음성 웨이크 단어 (게이트웨이 소유) 및 노드 간 동기화 방법"},"headers":[],"relativePath":"nodes/voicewake.md","filePath":"nodes/voicewake.md","lastUpdated":null}'),o={name:"nodes/voicewake.md"};function l(n,i,r,d,h,c){return e(),s("div",null,[...i[0]||(i[0]=[t('<h1 id="음성-웨이크-전역-웨이크-단어" tabindex="-1">음성 웨이크 (전역 웨이크 단어) <a class="header-anchor" href="#음성-웨이크-전역-웨이크-단어" aria-label="Permalink to &quot;음성 웨이크 (전역 웨이크 단어)&quot;">​</a></h1><p>OpenClaw는 <strong>웨이크 단어를 게이트웨이</strong>가 소유하는 <strong>단일 전역 목록</strong>으로 처리합니다.</p><ul><li><strong>노드별 사용자 정의 웨이크 단어는 없습니다</strong>.</li><li><strong>모든 노드/앱 UI가 목록을 편집할 수 있습니다.</strong> 변경 사항은 게이트웨이에 의해 유지되고 모두에게 브로드캐스트됩니다.</li><li>macOS와 iOS는 로컬 <strong>음성 웨이크 활성화/비활성화</strong> 토글을 유지합니다 (로컬 UX + 권한이 다름).</li><li>Android는 현재 음성 웨이크를 꺼둔 상태로 두고 음성 탭에서 수동 마이크 흐름을 사용합니다.</li></ul><h2 id="저장소-게이트웨이-호스트" tabindex="-1">저장소 (게이트웨이 호스트) <a class="header-anchor" href="#저장소-게이트웨이-호스트" aria-label="Permalink to &quot;저장소 (게이트웨이 호스트)&quot;">​</a></h2><p>웨이크 단어는 게이트웨이 머신에 저장됩니다:</p><ul><li><code>~/.openclaw/settings/voicewake.json</code></li></ul><p>형식:</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{ </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;triggers&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;openclaw&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;claude&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;computer&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">], </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;updatedAtMs&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1730000000000</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> }</span></span></code></pre></div><h2 id="프로토콜" tabindex="-1">프로토콜 <a class="header-anchor" href="#프로토콜" aria-label="Permalink to &quot;프로토콜&quot;">​</a></h2><h3 id="메서드" tabindex="-1">메서드 <a class="header-anchor" href="#메서드" aria-label="Permalink to &quot;메서드&quot;">​</a></h3><ul><li><code>voicewake.get</code> → <code>{ triggers: string[] }</code></li><li><code>voicewake.set</code> 매개변수 <code>{ triggers: string[] }</code> → <code>{ triggers: string[] }</code></li></ul><p>참고:</p><ul><li>트리거는 정규화됩니다 (트리밍, 비어 있는 항목 제거). 빈 목록은 기본값으로 폴백합니다.</li><li>안전을 위해 제한이 적용됩니다 (수/길이 제한).</li></ul><h3 id="이벤트" tabindex="-1">이벤트 <a class="header-anchor" href="#이벤트" aria-label="Permalink to &quot;이벤트&quot;">​</a></h3><ul><li><code>voicewake.changed</code> 페이로드 <code>{ triggers: string[] }</code></li></ul><p>수신하는 대상:</p><ul><li>모든 WebSocket 클라이언트 (macOS 앱, WebChat 등)</li><li>모든 연결된 노드 (iOS/Android), 그리고 노드 연결 시 초기 &quot;현재 상태&quot; 푸시.</li></ul><h2 id="클라이언트-동작" tabindex="-1">클라이언트 동작 <a class="header-anchor" href="#클라이언트-동작" aria-label="Permalink to &quot;클라이언트 동작&quot;">​</a></h2><h3 id="macos-앱" tabindex="-1">macOS 앱 <a class="header-anchor" href="#macos-앱" aria-label="Permalink to &quot;macOS 앱&quot;">​</a></h3><ul><li>전역 목록을 사용하여 <code>VoiceWakeRuntime</code> 트리거를 게이팅합니다.</li><li>음성 웨이크 설정에서 &quot;트리거 단어&quot; 편집 시 <code>voicewake.set</code>을 호출하고 다른 클라이언트와 동기화를 유지하기 위해 브로드캐스트에 의존합니다.</li></ul><h3 id="ios-노드" tabindex="-1">iOS 노드 <a class="header-anchor" href="#ios-노드" aria-label="Permalink to &quot;iOS 노드&quot;">​</a></h3><ul><li>전역 목록을 사용하여 <code>VoiceWakeManager</code> 트리거 감지를 수행합니다.</li><li>설정에서 웨이크 단어 편집 시 (게이트웨이 WS를 통해) <code>voicewake.set</code>을 호출하고 로컬 웨이크 단어 감지도 반응하게 유지합니다.</li></ul><h3 id="android-노드" tabindex="-1">Android 노드 <a class="header-anchor" href="#android-노드" aria-label="Permalink to &quot;Android 노드&quot;">​</a></h3><ul><li>음성 웨이크는 현재 Android 런타임/설정에서 비활성화되어 있습니다.</li><li>Android 음성은 웨이크 단어 트리거 대신 음성 탭의 수동 마이크 캡처를 사용합니다.</li></ul>',24)])])}const u=a(o,[["render",l]]);export{p as __pageData,u as default};
